import{_ as a,o as i,c as e,ae as s}from"./chunks/framework.B2m0-DLt.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/AI/skill.md","filePath":"note/AI/skill.md"}'),t={name:"note/AI/skill.md"};function r(n,l,o,p,d,h){return i(),e("div",null,[...l[0]||(l[0]=[s(`<h2 id="skills-是什么" tabindex="-1">skills 是什么 <a class="header-anchor" href="#skills-是什么" aria-label="Permalink to &quot;skills 是什么&quot;">​</a></h2><p>Skills 把「长期积累的经验、规则、最佳实践」封装成一套可复用、可组合、可触发的技能</p><p>你可以把Skills理解为：</p><ul><li>AI的「专业知识模块」</li><li>AI的「长期记忆 + 行为约束」</li><li>甚至是某个技术栈的「官方用法说明书（AI 版）」</li></ul><h2 id="skills-特点" tabindex="-1">skills 特点 <a class="header-anchor" href="#skills-特点" aria-label="Permalink to &quot;skills 特点&quot;">​</a></h2><p>优点：</p><ul><li>渐进式加载：先读头部源信息 -&gt; 读框架总览 -&gt; 具体框架内容</li></ul><p>缺点：</p><ul><li>标准统一，位置割裂。不同 AI 工具目录各异，跨平台使用不便</li><li>文件臃肿，无法渐进加载。大一统文件阻碍流动，难以分批到达</li><li>索引缺失，命名不明导致低效查询。命名混乱无索引，被迫加载多文件试错。</li><li>多 skills 冲突：过度安装的隐患。经验不足导致功能重叠，引发决策困境，效果很差。</li><li>存在相似技能时，缺乏智能提示，导致重复或冲突（未智能）</li></ul><h2 id="使用效果" tabindex="-1">使用效果 <a class="header-anchor" href="#使用效果" aria-label="Permalink to &quot;使用效果&quot;">​</a></h2><ul><li>强模型 + 好 Skills：模型底子好，Skills 如虎添翼，效果拔群。</li><li>弱模型 + 好 Skills：模型能力差，Skills 难以发挥，“巧妇难为无米之炊”</li></ul><h2 id="skills-文件夹" tabindex="-1">skills 文件夹 <a class="header-anchor" href="#skills-文件夹" aria-label="Permalink to &quot;skills 文件夹&quot;">​</a></h2><p>头部元信息：</p><ul><li>name: 技能名称</li><li>description: 描述：何时用，提供能力</li></ul><p>正文内容</p><ul><li>技能流程</li><li>相关信息</li><li>文件说明</li></ul><p>资源文件夹（辅助内容）</p><ul><li>examples(示例)</li><li>templates(模版)</li><li>scripts（脚本）</li><li>reference.md（索引）</li></ul><h2 id="打造专属-skill" tabindex="-1">打造专属 Skill <a class="header-anchor" href="#打造专属-skill" aria-label="Permalink to &quot;打造专属 Skill&quot;">​</a></h2><ul><li>现成 Skills 的烦恼：质量不一，不适用，找不到</li><li>打造我的专属 Skills，基于个人需求，快速构建</li></ul><h2 id="skill-md-组成" tabindex="-1">SKILL.md 组成 <a class="header-anchor" href="#skill-md-组成" aria-label="Permalink to &quot;SKILL.md 组成&quot;">​</a></h2><h3 id="frontmatter-yaml-元信息" tabindex="-1">FrontMatter(YAML 元信息) <a class="header-anchor" href="#frontmatter-yaml-元信息" aria-label="Permalink to &quot;FrontMatter(YAML 元信息)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>---</span></span>
<span class="line"><span>name: 技能名称</span></span>
<span class="line"><span>description: 描述：能干什么，何时用，比如当用户提到周报、weekly report、本周总结时使用</span></span>
<span class="line"><span>---</span></span></code></pre></div><p>可选字段：</p><ul><li>allowed-tools: 允许使用哪些工具</li><li>context: 需要加载的上下文文件</li><li>user-invocable: 是否可被用户直接调用</li></ul><h3 id="执行流程-markdown-正文" tabindex="-1">执行流程（markdown 正文） <a class="header-anchor" href="#执行流程-markdown-正文" aria-label="Permalink to &quot;执行流程（markdown 正文）&quot;">​</a></h3><p>skill 核心内容，告诉 AI 具体怎么做：先问什么，再做什么，输出什么格式，有什么约束。</p><h2 id="和-system-prompt-区别" tabindex="-1">和 System Prompt 区别 <a class="header-anchor" href="#和-system-prompt-区别" aria-label="Permalink to &quot;和 System Prompt 区别&quot;">​</a></h2><ul><li>System Prompt 特点：全局、永久加载，比如在 CLAUDE.md 写的所有规则，每一轮 AI 都会看到</li><li>Skill 是模块化的，按需加载。</li></ul><h2 id="和-mcp-区别" tabindex="-1">和 MCP 区别 <a class="header-anchor" href="#和-mcp-区别" aria-label="Permalink to &quot;和 MCP 区别&quot;">​</a></h2><ul><li>MCP：能力接口</li><li>Skill：知识和流程</li></ul>`,31)])])}const u=a(t,[["render",r]]);export{c as __pageData,u as default};
